class Solution:
    def largestMagicSquare(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        m, n = len(grid), len(grid[0])
        if m < 2 or n < 2:
            return 0

        max_size = 0

        # Check all 2x2 squares as base
        for i in range(m - 1):
            for j in range(n - 1):
                # Check magic square of size k centered around i,j
                for k in range(2, min(m - i, n - j) + 1):
                    # Get square boundaries
                    top, left = i - k//2 + 1, j - k//2 + 1
                    bottom, right = top + k - 1, left + k - 1

                    if top < 0 or bottom >= m or left < 0 or right >= n:
                        continue

                    # Check if magic square
                    target = None
                    is_magic = True

                    # Row sums
                    for r in range(top, bottom + 1):
                        row_sum = sum(grid[r][c] for c in range(left, right + 1))
                        if target is None:
                            target = row_sum
                        elif target != row_sum:
                            is_magic = False
                            break

                    # Column sums
                    if is_magic:
                        for c in range(left, right + 1):
                            col_sum = sum(grid[r][c] for r in range(top, bottom + 1))
                            if target != col_sum:
                                is_magic = False
                                break

                    # Diagonal sums
                    if is_magic:
                        diag1 = sum(grid[top + di][left + di] for di in range(k))
                        diag2 = sum(grid[top + di][right - di] for di in range(k))
                        if diag1 != target or diag2 != target:
                            is_magic = False

                    if is_magic:
                        max_size = max(max_size, k)

        return max_size
